// 初始化后把本实例新增 CSS 迁入 shadow(铁律 2)
import { emojiBlast } from 'https://cdn.jsdelivr.net/npm/emoji-blast@0/+esm';
const el = document.createElement('div'); el.style.cssText = `position:relative;height:${spec.height ?? 400}px;overflow:hidden;transform:translateZ(0)`; shadowRoot.appendChild(el);
const className = `ov-emoji-${crypto.randomUUID()}`, before = new Set(document.head.querySelectorAll('style'));
const position = data.options?.position ?? { x: (el.clientWidth || 640) / 2, y: (spec.height ?? 400) * 0.7 };
const handle = emojiBlast({ ...(data.options ?? {}), className, container: el, position });
for (const s of document.head.querySelectorAll('style')) if (!before.has(s) && s.textContent.includes(`.${className}`)) shadowRoot.appendChild(s);

